import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  getAllSupportsApi,
  getMySupportsApi,
  updateSupportStatusApi
} from '../api/apiServices';

import RequestCard from '../components/RequestCard';
import RequestDetailModal from '../components/RequestDetailModal';
import FilterBar from '../components/FilterBar';

const RequestList = () => {
  const navigate = useNavigate();

  const [activeTab, setActiveTab] = useState('ALL');
  const [statusFilter, setStatusFilter] = useState('ALL');
  const [requests, setRequests] = useState([]);
  const [myRequests, setMyRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedReq, setSelectedReq] = useState(null);

  const currentUser = JSON.parse(localStorage.getItem('user') || '{}');

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
      const [allRes, myRes] = await Promise.all([
        getAllSupportsApi().catch(() => ({ data: [] })),
        getMySupportsApi().catch(() => ({ data: [] }))
      ]);

      setRequests(allRes.data || []);
      setMyRequests(myRes.data || []);
    } catch (err) {
      console.error(err);
    }
    setLoading(false);
  };

  const getFilteredRequests = () => {
    let list = [];

    if (activeTab === 'ALL') {
      list = [...requests];
    } else if (activeTab === 'MINE') {
      list = [...myRequests];
    } else {
      const myIds = new Set(myRequests.map((r) => r.id));
      list = requests.filter((r) => !myIds.has(r.id));
    }

    if (statusFilter !== 'ALL') {
      list = list.filter((r) => r.status === statusFilter);
    }

    return list.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
  };

  const filtered = getFilteredRequests();

  const handleUpdateStatus = async (id, newStatus) => {
    try {
      await updateSupportStatusApi(id, newStatus);
      await fetchData();
      setSelectedReq(null);
    } catch (err) {
      console.error(err);
      alert('Cập nhật trạng thái thất bại');
    }
  };

  const handleOpenMap = (req) => {
    navigate('/', {
      state: {
        routeToDest: { lat: req.latitude, lng: req.longitude }
      }
    });
  };

  return (
    <div className="container" style={{ paddingTop: '32px', paddingBottom: '40px' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '28px' }}>
        <h2 style={{ margin: 0, fontSize: '2rem', fontWeight: '800', color: '#0F172A' }}>
          Danh sách yêu cầu
        </h2>
      </div>

      <FilterBar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        statusFilter={statusFilter} 
        setStatusFilter={setStatusFilter} 
      />

      {loading ? (
        <p style={{ color: '#64748B' }}>Đang tải dữ liệu...</p>
      ) : filtered.length === 0 ? (
        <div style={{ background: 'white', borderRadius: '16px', padding: '40px', textAlign: 'center', color: '#94A3B8', border: '1px solid #E2E8F0' }}>
          Không có yêu cầu phù hợp.
        </div>
      ) : (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(340px, 1fr))', gap: '20px' }}>
          {filtered.map((r) => {
            const isMine = myRequests.some((m) => m.id === r.id);
            return (
              <RequestCard 
                key={r.id} 
                req={r} 
                isMine={isMine} 
                onClick={(reqData) => setSelectedReq({ ...reqData, isMine })} 
              />
            );
          })}
        </div>
      )}

      {selectedReq && (
        <RequestDetailModal
          req={selectedReq}
          onClose={() => setSelectedReq(null)}
          onUpdateStatus={handleUpdateStatus}
          onOpenMap={handleOpenMap}
          currentUser={currentUser}
        />
      )}
    </div>
  );
};

export default RequestList;
